const callWrapper = (name, ret, args, isAsync) => {
  const fn = Module.cwrap(
    name,
    ret,
    args,
    isAsync ? { async: true } : undefined
  );
  return async (...callArgs) => {
    let result;
    try {
      result = isAsync ? await fn(...callArgs) : fn(...callArgs);
    } catch (ex) {
      console.error(ex);
      throw ex;
    }
    return result;
  };
};

